import{_ as e,o as s,c as n,ag as t}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Control Flow","description":"","frontmatter":{},"headers":[],"relativePath":"language/language_reference/control_flow.md","filePath":"language/language_reference/control_flow.md"}'),o={name:"language/language_reference/control_flow.md"};function l(i,a,d,c,p,r){return s(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="control-flow" tabindex="-1">Control Flow <a class="header-anchor" href="#control-flow" aria-label="Permalink to &quot;Control Flow&quot;">​</a></h1><p>Control flow constructs direct the execution path of a Bliss program. All control flow constructs are <strong>statements</strong> — they produce no value.</p><h2 id="conditions" tabindex="-1">Conditions <a class="header-anchor" href="#conditions" aria-label="Permalink to &quot;Conditions&quot;">​</a></h2><p>Both <code>if</code> and <code>while</code> require a condition. A condition must be a <strong>boolean expression</strong> — any expression that evaluates to a value of type <code>bool</code>. Since Bliss has built-in <code>true</code> and <code>false</code>, the condition must resolve to one of these values. Arithmetic or other non-boolean expressions are not valid conditions.</p><table tabindex="0"><thead><tr><th>Expression</th><th>Valid?</th><th>Reason</th></tr></thead><tbody><tr><td><code>x &gt; 5</code></td><td>✅</td><td>Comparison returns <code>bool</code></td></tr><tr><td><code>isReady</code></td><td>✅</td><td>Variable of type <code>bool</code></td></tr><tr><td><code>true</code></td><td>✅</td><td>Built-in boolean literal</td></tr><tr><td><code>x + 5</code></td><td>❌</td><td>Returns a number, not <code>bool</code></td></tr><tr><td><code>x + 1</code></td><td>❌</td><td>Returns a number, not <code>bool</code></td></tr></tbody></table><hr><h2 id="conditionals" tabindex="-1">Conditionals <a class="header-anchor" href="#conditionals" aria-label="Permalink to &quot;Conditionals&quot;">​</a></h2><p>Bliss uses standard conditional branching with <code>if</code>, <code>elif</code>, and <code>else</code>.</p><h3 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if ( &lt;condition&gt; ) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>} elif ( &lt;condition&gt; ) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li><code>if</code> can stand alone.</li><li><code>elif</code> and <code>else</code> must be preceded by an <code>if</code> (or another <code>elif</code>).</li><li>Each <code>&lt;condition&gt;</code> must satisfy the condition rules defined above.</li></ul><h3 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if ( x &gt; 5 ) {</span></span>
<span class="line"><span>    // runs when x is greater than 5</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>if ( x &gt; 10 ) {</span></span>
<span class="line"><span>    // x is greater than 10</span></span>
<span class="line"><span>} elif ( x &gt; 5 ) {</span></span>
<span class="line"><span>    // x is between 6 and 10</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>    // x is 5 or less</span></span>
<span class="line"><span>}</span></span></code></pre></div><hr><h2 id="loops" tabindex="-1">Loops <a class="header-anchor" href="#loops" aria-label="Permalink to &quot;Loops&quot;">​</a></h2><p>Bliss has a single loop construct: the <code>while</code> loop.</p><h3 id="syntax-1" tabindex="-1">Syntax <a class="header-anchor" href="#syntax-1" aria-label="Permalink to &quot;Syntax&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>while ( &lt;condition&gt; ) {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre></div><h3 id="rules-1" tabindex="-1">Rules <a class="header-anchor" href="#rules-1" aria-label="Permalink to &quot;Rules&quot;">​</a></h3><ul><li>The <code>&lt;condition&gt;</code> must satisfy the condition rules defined above.</li><li>The loop body executes repeatedly for as long as the condition remains <code>true</code>.</li><li>If the condition is <code>false</code> on the first check, the body never executes.</li></ul><h3 id="examples-1" tabindex="-1">Examples <a class="header-anchor" href="#examples-1" aria-label="Permalink to &quot;Examples&quot;">​</a></h3><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>while ( x &gt; 0 ) {</span></span>
<span class="line"><span>    // runs until x is no longer greater than 0</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="language-bls vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bls</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>while ( true ) {</span></span>
<span class="line"><span>    // infinite loop</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,25)])])}const b=e(o,[["render",l]]);export{u as __pageData,b as default};
